const results = $input.all().map(i => i.json);
const firstItem = results[0];
if (!firstItem || !firstItem.videoUrl) {
  const dbg = JSON.stringify(firstItem || {}).slice(0, 800);
  throw new Error('Could not find a downloadable media URL on the Frame.io page. ' + dbg);
}
let url = String(firstItem.videoUrl).replace(/&amp;/g, '&');
return [{ json: { mediaUrl: url, _scrapeStats: { audioCount: firstItem.audioCount, combinedCount: firstItem.combinedCount, originalCount: firstItem.originalCount, videoOnlyCount: firstItem.videoOnlyCount, totalCount: firstItem.totalCount } } }];

const incoming = $input.first() && $input.first().json;
if (!incoming) throw new Error('Empty response from Replicate');
// When the Wait-for-webhook node resumes, the body field carries Replicate's callback payload (the full prediction object). On the rare path where the Wait timed out and just passed the original submit-prediction response through, the payload is at top level instead. Handle both.
const pred = (incoming.body && typeof incoming.body === 'object') ? incoming.body : incoming;
if (pred.status && pred.status !== 'succeeded') {
  throw new Error('Replicate run ' + pred.status + (pred.error ? ': ' + String(pred.error).slice(0, 240) : ''));
}
const out = pred.output;
if (out == null) throw new Error('Replicate returned no output (status=' + (pred.status || 'unknown') + ')');
let transcript = '';
if (typeof out === 'string') transcript = out;
else if (typeof out.transcription === 'string') transcript = out.transcription;
else if (typeof out.text === 'string') transcript = out.text;
else if (Array.isArray(out)) transcript = out.map(x => (x && (x.text || x.transcription)) || '').join(' ');
else if (typeof out === 'object') transcript = String(out.translation || out.transcription || out.text || '');
transcript = transcript.trim();
if (!transcript) throw new Error('Replicate returned an empty transcript');
return [{ json: { transcript } }];

const ctx = $('Prepare Apify Input').first().json;
const caption = ($input.first() && $input.first().json && $input.first().json.caption) || '';
const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://synchrosocial.app.n8n.cloud/webhook/calendar-upsert-post',
  body: { client: ctx.client, post: { id: ctx.postId, caption: caption } },
  json: true,
  timeout: 30000
});
if (!resp || resp.ok !== true) {
  throw new Error('calendar-upsert-post returned non-ok: ' + JSON.stringify(resp).slice(0, 300));
}
return [{ json: { ok: true, client: ctx.client, postId: ctx.postId, caption, savedToSheet: true } }];
